let valores = flow.get("vapor") || {};
let data = Array.isArray(msg.payload) ? msg.payload : [msg.payload];

for (const p of data) {
  if (!p) continue;

  const id = p.id || p.name || p.tag || p.topic || msg.topic;
  const cfg = scales[id];

  const raw = Number(
    p.value_raw !== undefined ? p.value_raw :
    p.value !== undefined ? p.value :
    p.v !== undefined ? p.v :
    p
  );

  if (!Number.isFinite(raw)) continue;

  let value = raw;
  let unit = "raw";

  if (cfg) {
    // Escalado
    value = ((raw - cfg.rawMin) * (cfg.engMax - cfg.engMin)) / 
            (cfg.rawMax - cfg.rawMin) + cfg.engMin;

    // 🔴 Clamp completo (evita negativos y valores fuera de rango)
    value = Math.max(cfg.engMin, Math.min(cfg.engMax, value));

    // Redondeo
    value = Number(value.toFixed(3));
    unit = cfg.unit;
  }

  valores[id] = {
    value: value,
    raw: raw,
    unit: unit,
    timestamp: new Date().toISOString()
  };
}

flow.set("vapor", valores);
return null;

