function get(area, tag) {
    let x = area[tag];
    if (!x) return null;

    if (typeof x === "object") {
        let n = Number(x.value);
        if (!Number.isFinite(n)) return null;
        return {
            value: n,
            unit: x.unit || ""
        };
    }

    let n = Number(x);
    if (!Number.isFinite(n)) return null;
    return {
        value: n,
        unit: ""
    };
}

function val(area, tag, dec = 1) {
    let x = get(area, tag);
    if (!x) return "sin dato";
    return x.value.toFixed(dec) + (x.unit ? " " + x.unit : "");
}

function num(area, tag) {
    let x = get(area, tag);
    return x ? x.value : 0;
}

function estadoTexto(condicion) {
    return condicion ? "en funcionamiento" : "parado";
}

function cerrar(texto) {
    msg.alexaText = texto;

    // Formato más simple para Alexa Routine: usar msg.payload como texto a decir.
    msg.payload = texto;

    // Formato alternativo por si tu nodo Alexa Routine usa objeto tipo speak.
    msg.alexaRoutinePayload = {
        type: "speak",
        payload: {
            type: "regular",
            text: texto
        }
    };

    return msg;
}

